DEFAULT_CIPHERS = ":".join(
    [
        "ECDHE+AESGCM",
        "ECDHE+CHACHA20",
        "DHE+AESGCM",
        "DHE+CHACHA20",
        "ECDH+AESGCM",
        "DH+AESGCM",
        "ECDH+AES",
        "DH+AES",
        "RSA+AESGCM",
        "RSA+AES",
        "!aNULL",
        "!eNULL",
        "!MD5",
        "!DSS",
    ]
)


logger = logging.getLogger("httpx")


class UnsetType:
    pass  # pragma: no cover


UNSET = UnsetType()


def create_ssl_context(
    cert: typing.Optional[CertTypes] = None,
    verify: VerifyTypes = True,
    trust_env: bool = True,
    http2: bool = False,
) -> ssl.SSLContext:
    """Create and return an SSLContext configured according to the given options.

    This convenience helper constructs an SSLConfig from the provided options and
    returns its prepared SSLContext instance.
    """
    return SSLConfig(
        cert=cert, verify=verify, trust_env=trust_env, http2=http2
    ).ssl_context


class SSLConfig:
    """
    SSL Configuration.
    """

    DEFAULT_CA_BUNDLE_PATH = Path(certifi.where())

    def __init__(
        self,
        *,
        cert: typing.Optional[CertTypes] = None,
        verify: VerifyTypes = True,
        trust_env: bool = True,
        http2: bool = False,
    ) -> None:
        """Initialize an SSLConfig.

        Args:
            cert: Client certificate configuration (file path, tuple of (cert, key), or None).
            verify: Whether to verify server certificates, a path to a CA bundle, or an SSLContext.
            trust_env: Whether to respect environment variables to locate CA bundles.
            http2: Whether the context is intended for HTTP/2 (used to pick ciphers).
        """
        self.cert = cert
        self.verify = verify
        self.trust_env = trust_env
        self.http2 = http2
        self.ssl_context = self.load_ssl_context()

    def load_ssl_context(self) -> ssl.SSLContext:
        """Load and return a configured SSLContext based on this configuration.

        Chooses between a context that verifies certificates and one that does
        not, and also supports passing in a pre-configured SSLContext.
        """
        logger.debug(
            "load_ssl_context verify=%r cert=%r trust_env=%r http2=%r",
            self.verify,
            self.cert,
            self.trust_env,
            self.http2,
        )

        if self.verify:
            return self.load_ssl_context_verify()
        return self.load_ssl_context_no_verify()

    def load_ssl_context_no_verify(self) -> ssl.SSLContext:
        """
        Return an SSL context for unverified connections.
        """
        context = self._create_default_ssl_context()
        context.check_hostname = False
        context.verify_mode = ssl.CERT_NONE
        self._load_client_certs(context)
        return context

    def load_ssl_context_verify(self) -> ssl.SSLContext:
        """
        Return an SSL context for verified connections.
        """
        if self.trust_env and self.verify is True:
            ca_bundle = get_ca_bundle_from_env()
            if ca_bundle is not None:
                self.verify = ca_bundle

        if isinstance(self.verify, ssl.SSLContext):
            # Allow passing in our own SSLContext object that's pre-configured.
            context = self.verify
            self._load_client_certs(context)
            return context
        elif isinstance(self.verify, bool):
            ca_bundle_path = self.DEFAULT_CA_BUNDLE_PATH
        elif Path(self.verify).exists():
            ca_bundle_path = Path(self.verify)
        else:
            raise IOError(
                "Could not find a suitable TLS CA certificate bundle, "
                "invalid path: {}".format(self.verify)
            )

        context = self._create_default_ssl_context()
        context.verify_mode = ssl.CERT_REQUIRED
        context.check_hostname = True

        # Signal to server support for PHA in TLS 1.3. Raises an
        # AttributeError if only read-only access is implemented.
        try:
            context.post_handshake_auth = True
        except AttributeError:  # pragma: no cover
            pass

        # Disable using 'commonName' for SSLContext.check_hostname
        # when the 'subjectAltName' extension isn't available.
        try:
            context.hostname_checks_common_name = False
        except AttributeError:  # pragma: no cover
            pass

        if ca_bundle_path.is_file():
            cafile = str(ca_bundle_path)
            logger.debug("load_verify_locations cafile=%r", cafile)
            context.load_verify_locations(cafile=cafile)
        elif ca_bundle_path.is_dir():
            capath = str(ca_bundle_path)
            logger.debug("load_verify_locations capath=%r", capath)
            context.load_verify_locations(capath=capath)
        else:  # pragma: no cover - defensive
            raise IOError(
                "Could not load CA bundle from: {}".format(ca_bundle_path)
            )

        self._load_client_certs(context)
        return context

    def _create_default_ssl_context(self) -> ssl.SSLContext:
        """Create a default SSL context with secure options and ciphers applied.

        Ensures a minimum TLS version is enforced and configures cipher suites
        appropriate for HTTP/1.1 and HTTP/2 usage.
        """
        context = ssl.create_default_context(ssl.Purpose.SERVER_AUTH)

        # Enforce a minimum TLS version (1.2) when possible.
        try:
            set_minimum_tls_version_1_2(context)
        except Exception:
            # If setting the minimum TLS version is not supported, rely on defaults.
            logger.debug("Could not set minimum TLS version to 1.2 on this platform.")

        # Configure ciphers: prefer modern AEAD and ChaCha20 suites.
        try:
            # For HTTP/2 we need a stricter set of ciphers; otherwise use DEFAULT_CIPHERS.
            context.set_ciphers(DEFAULT_CIPHERS)
        except ssl.SSLError:
            # If setting ciphers fails, continue with defaults.
            logger.debug("Setting SSL ciphers failed; using platform defaults.")

        # Disable older, less secure protocols and options where available.
        try:
            context.options |= ssl.OP_NO_COMPRESSION
        except Exception:
            # Not all platforms expose OP_NO_COMPRESSION
            pass

        return context

    def _load_client_certs(self, context: ssl.SSLContext) -> None:
        """Load client-side certificates into the SSL context if provided.

        The cert parameter may be:
        - None: no client certs.
        - A path to a PEM file containing both cert and private key.
        - A tuple of (certfile, keyfile).
        - A tuple of bytes or in-memory objects is not supported here and will be ignored.
        """
        if not self.cert:
            return

        try:
            if isinstance(self.cert, (list, tuple)):
                # (certfile, keyfile)
                certfile = self.cert[0]
                keyfile = self.cert[1] if len(self.cert) > 1 else None
                logger.debug("Loading client certfile=%r keyfile=%r", certfile, keyfile)
                context.load_cert_chain(certfile=certfile, keyfile=keyfile)
            elif isinstance(self.cert, str) or isinstance(self.cert, Path):
                certfile = str(self.cert)
                logger.debug("Loading client certfile=%r", certfile)
                context.load_cert_chain(certfile=certfile)
            else:
                # Unsupported type: ignore or raise.
                logger.debug("Unsupported client cert type: %r", type(self.cert))
        except Exception:
            logger.exception("Failed to load client certificate(s) from %r", self.cert)


class Timeout:
    """Representation of individual timeout configuration for client operations."""

    DEFAULT_CONNECT = 5.0
    DEFAULT_READ = 5.0
    DEFAULT_WRITE = 5.0
    DEFAULT_POOL = None

    def __init__(
        self,
        *,
        connect: typing.Optional[float] = DEFAULT_CONNECT,
        read: typing.Optional[float] = DEFAULT_READ,
        write: typing.Optional[float] = DEFAULT_WRITE,
        pool: typing.Optional[float] = DEFAULT_POOL,
    ) -> None:
        """Initialize timeout configuration.

        Args:
            connect: Timeout for establishing a connection.
            read: Timeout for reading from a connection.
            write: Timeout for writing to a connection.
            pool: Timeout for acquiring a connection from the pool.
        """
        self.connect = connect
        self.read = read
        self.write = write
        self.pool = pool

    @classmethod
    def from_float(cls, value: typing.Optional[float]) -> typing.Optional["Timeout"]:
        """Create a Timeout where all timeouts are set to the same float value.

        Returns None if `value` is None.
        """
        if value is None:
            return None
        return cls(connect=value, read=value, write=value, pool=value)

    def as_dict(self) -> dict:
        """Return a dictionary representation of the timeout configuration."""
        return {"connect": self.connect, "read": self.read, "write": self.write, "pool": self.pool}

    def __eq__(self, other: object) -> bool:
        """Compare Timeout instances for equality based on their values."""
        if not isinstance(other, Timeout):
            return NotImplemented
        return self.as_dict() == other.as_dict()

    def __repr__(self) -> str:
        """Return an evaluable string representation of the timeout configuration."""
        return (
            f"Timeout(connect={self.connect!r}, read={self.read!r}, "
            f"write={self.write!r}, pool={self.pool!r})"
        )


class Limits:
    """Represents connection pool limits."""

    DEFAULT_MAX_KEEPALIVE = 5
    DEFAULT_MAX_CONNECTIONS = None

    def __init__(self, max_keepalive_connections: int = DEFAULT_MAX_KEEPALIVE, max_connections: typing.Optional[int] = DEFAULT_MAX_CONNECTIONS) -> None:
        """Initialize connection limits.

        Args:
            max_keepalive_connections: Maximum number of keep-alive connections to retain.
            max_connections: Maximum number of active connections (None means no explicit limit).
        """
        self.max_keepalive_connections = max_keepalive_connections
        self.max_connections = max_connections

    def as_dict(self) -> dict:
        """Return a dictionary representation of the limits."""
        return {"max_keepalive_connections": self.max_keepalive_connections, "max_connections": self.max_connections}

    def __eq__(self, other: object) -> bool:
        """Compare Limits instances for equality based on their values."""
        if not isinstance(other, Limits):
            return NotImplemented
        return self.as_dict() == other.as_dict()

    def __repr__(self) -> str:
        """Return a string representation of the limits instance."""
        return f"Limits(max_keepalive_connections={self.max_keepalive_connections!r}, max_connections={self.max_connections!r})"


class Auth:
    """Simple wrapper for carrying authentication credentials/callables."""

    def __init__(self, auth: typing.Union[typing.Tuple[str, str], typing.Callable, None]) -> None:
        """Initialize the Auth wrapper.

        Args:
            auth: A tuple of (username, password), a callable that implements auth,
                  or None for no authentication.
        """
        self._auth = auth

    def raw_auth(self) -> typing.Union[typing.Tuple[str, str], typing.Callable, None]:
        """Return the raw authentication object provided at initialization."""
        return self._auth

    def __repr__(self) -> str:
        """Return a representation of the Auth wrapper."""
        return f"Auth(auth={self._auth!r})"